Javascript.initialise:
 
			var nodes1 = Services.getNodes("/ds/wp/MaintainObligations/Obligations/Obligation/ObligationSeq");
			var max = 0;
			 
			var nodeValue;
			for( var i = 0; i < nodes1.length; i++ )
			{ 
				nodeValue = parseInt( XML.getNodeTextContent( nodes1[i] ) );
				 if (nodeValue > max)
				{
					max = nodeValue;
				}
			}						
		    var notesStg = Services.getValue("/ds/wp/MaintainObligations/Obligations/Obligation[./ObligationSeq = "+max+"]/Notes");				                              
		    obligationSeqNo = max;
		
			Services.setValue(FeeFor.dataBinding, notesStg);
